import math, torch

@torch.no_grad()
def perplexity(model, input_ids):
    """Compute perplexity on a tokenised batch of shape (1, T)."""
    loss, _ = model(input_ids)    # cross-entropy loss (average over T-1 tokens)
    return math.exp(loss.item())

# Example usage:
# ppl = perplexity(model, tokenizer.encode("The quick brown fox", return_tensors='pt'))
# A well-trained GPT-2 on WikiText-103 achieves ~17-18 PPL.
